mapper.select:
  	SELECT * FROM (
  		SELECT ROWNUM AS RNUM, A.*
  		FROM (
  			 SELECT B.BNO
  			 	  , B.TITLE
  			 	  , B.CONTENT
  			 	  , B.REGDATE
  			 	  , B.VIEWCNT
 			   FROM FREE_BOARD_TBL B
 			  WHERE B.USER_ID = #{userId}
 			  ORDER BY B.BNO DESC
  			  ) A
		WHERE ROWNUM <= #{endRow}
  	)
  	 WHERE RNUM >= #{starRow}

    SELECT * FROM (
    SELECT ROWNUM AS RNUM, A.*
      FROM (
            SELECT C.CNO
                 , C.BNO
                 , B.TITLE  AS boardTitle
                 , C.CONTENT
                 , C.REGDATE
              FROM FREE_COMMENT_TBL C
              JOIN FREE_BOARD_TBL   B ON C.BNO = B.BNO
             WHERE C.USER_ID = #{userId}
             ORDER BY C.CNO DESC
           ) A
     WHERE ROWNUM <= #{endRow}
)
 WHERE RNUM >= #{startRow}

