UPDATE USER_TBL
   SET NICKNAME = #{nickname}
 WHERE USER_ID  = #{userId}

UPDATE PROFILE_TBL

    UPDATED_AT = SYSDATE,
    BIRTH_DATE = #{birthDate},
    BIO = #{bio}

 WHERE USER_ID = #{userId}

UPDATE PROFILE_TBL
   SET PHOTO_URL  = #{photoUrl}
     , UPDATED_AT = SYSDATE
 WHERE USER_ID    = #{userId}
